// ══════════════════════════════════════════════════════════════
// EVEZ WF8 — arXiv CPF Scanner
// Pulls latest arXiv papers, scores each against CPF/EVEZ-OS,
// computes poly_c, generates FIRE events for poly_c >= 0.9
// poly_c = tau * omega * topo / (2 * sqrt(N))
// ══════════════════════════════════════════════════════════════

function H(d){let h=5381,s=typeof d==='string'?d:JSON.stringify(d);for(let i=0;i<s.length;i++){h=((h<<5)+h)+s.charCodeAt(i);h|=0;}return 'sha_'+Math.abs(h).toString(16).padStart(16,'0');}
async function log(t,p){try{await $fetch('https://evezos.app.n8n.cloud/webhook/evez-ledger',{method:'POST',body:{event_type:t,payload:{...p,pid:335,ts:new Date().toISOString()}}});}catch(e){}}
async function groq(sys,usr,model='llama-3.1-8b-instant',max=1000){
  const k=$env.GROQ_API_KEY||'';
  if(!k)return{error:'No GROQ_API_KEY'};
  try{
    const r=await $fetch('https://api.groq.com/openai/v1/chat/completions',{
      method:'POST',
      headers:{'Authorization':`Bearer ${k}`,'Content-Type':'application/json'},
      body:JSON.stringify({model,max_tokens:max,messages:[{role:'system',content:sys},{role:'user',content:usr}]})
    });
    const t=r.choices?.[0]?.message?.content||'{}';
    try{return JSON.parse(t.replace(/```json|```/g,'').trim());}catch{return{raw:t};}
  }catch(e){return{error:e.message};}
}
async function gemini(sys,usr,max=1000){
  const k=$env.GEMINI_API_KEY||'';
  if(!k)return{error:'No GEMINI_API_KEY'};
  try{
    const r=await $fetch(`https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${k}`,{
      method:'POST',headers:{'Content-Type':'application/json'},
      body:JSON.stringify({systemInstruction:{parts:[{text:sys}]},contents:[{role:'user',parts:[{text:usr}]}],generationConfig:{maxOutputTokens:max}})
    });
    const t=r.candidates?.[0]?.content?.parts?.[0]?.text||'{}';
    try{return JSON.parse(t.replace(/```json|```/g,'').trim());}catch{return{raw:t};}
  }catch(e){return{error:e.message};}
}

const ts = new Date().toISOString();
const b = $input.first()?.json?.body || {};

// ── QUERY CONFIGURATION ─────────────────────────────────────────────────────
// These are the CPF/EVEZ-OS semantic fingerprints
const EVEZ_QUERIES = [
  // Multi-agent + context (DACS family)
  'cat:cs.MA+AND+(multi-agent+OR+context+scoping+OR+orchestration)',
  // Oscillator / phase dynamics (KoPE family)
  'cat:cs.LG+AND+(oscillat+OR+kuramoto+OR+phase+encoding+OR+synchroni)',
  // Attention-free / token-free (Kathleen family)
  'cat:cs.CL+AND+(attention+free+OR+oscillator+OR+byte+level+OR+tokeniz)',
  // Physics-embedded / endogenous (MPPA family)
  'cat:cs.AI+AND+(meta+principle+OR+endogenous+OR+physics+architecture+OR+conservation)',
  // Quantum temporal / topology (QTM family)
  'cat:quant-ph+AND+(temporal+OR+topology+OR+entanglement+OR+phase)',
  // Autonomous systems / self-modifying (EVEZ-OS family)
  'cat:cs.AI+AND+(autonomous+agent+OR+self+improving+OR+falsif+OR+falsifiable)',
];

// Pick query for this run (rotate weekly by slot)
const slot = Math.floor(Date.now() / (7*24*3600*1000));
const query = b.query || EVEZ_QUERIES[slot % EVEZ_QUERIES.length];
const maxResults = parseInt(b.max_results || '15');

// ── FETCH FROM arXiv API ─────────────────────────────────────────────────────
let papers = [];
try {
  const url = `https://export.arxiv.org/api/query?search_query=${encodeURIComponent(query)}&start=0&max_results=${maxResults}&sortBy=submittedDate&sortOrder=descending`;
  const xml = await $fetch(url, {method:'GET', headers:{'Accept':'application/xml'}});

  // Parse Atom XML
  const entries = (xml.match(/<entry>[\s\S]*?<\/entry>/g) || []);

  for (const entry of entries) {
    const id      = (entry.match(/<id>([^<]+)<\/id>/) || [])[1]?.split('/abs/')[1] || '';
    const title   = (entry.match(/<title>([\s\S]*?)<\/title>/) || [])[1]?.replace(/\s+/g,' ').trim() || '';
    const summary = (entry.match(/<summary>([\s\S]*?)<\/summary>/) || [])[1]?.replace(/\s+/g,' ').trim() || '';
    const cats    = [...entry.matchAll(/<category term="([^"]+)"/g)].map(m=>m[1]);
    const pub     = (entry.match(/<published>([^<]+)<\/published>/) || [])[1] || '';
    const link    = (entry.match(/<link[^>]+href="([^"]+)"[^>]+title="pdf"/) || [])[1] || `https://arxiv.org/abs/${id.split('v')[0]}`;
    const authors = [...entry.matchAll(/<name>([^<]+)<\/name>/g)].map(m=>m[1]).slice(0,3);

    if (id && title) {
      papers.push({id, title, abstract: summary.slice(0,800), categories: cats, published: pub, url: link, authors});
    }
  }
} catch(e) {
  await log('ARXIV_FETCH_ERROR', {error: e.message, query});
  return [{json:{error: 'arXiv fetch failed', detail: e.message, query}}];
}

if (!papers.length) {
  await log('ARXIV_SCAN_EMPTY', {query, slot});
  return [{json:{papers_found:0, query, note:'No results — try different query'}}];
}

// ── CPF SCORING ENGINE ───────────────────────────────────────────────────────
// Score each paper against EVEZ-OS dimensions without calling an LLM
// (pure signal extraction — saves API budget for genuine FIRE events)

const EVEZ_SIGNALS = [
  // tau: cycle detection, frequency, triggering — validated: KoPE, Kathleen
  {dim:'tau', weight:1.0, terms:['oscillat','kuramoto','frequency','periodic','cycl','resonan','temporal','rhythm','trigger','threshold','crossing','session','transition','event-driven','fire']},
  // omega: phase, coherence, coordination — validated: KoPE, DACS
  {dim:'omega', weight:1.0, terms:['phase','synchroni','coherent','coupling','entangle','alignment','binding','coordinat','steering','context window','scoping','isolation','lock','focus']},
  // topo: graph structure, hierarchy — validated: all 4
  {dim:'topo', weight:1.0, terms:['topolog','graph','manifold','lattice','mesh','network','hierarchi','tree','registry','asymmetric','architecture','layer','structure','routing','circuit']},
  // N: distributed, multi-agent, ensemble — validated: DACS, KoPE
  {dim:'N', weight:1.0, terms:['multi-agent','distributed','ensemble','swarm','parallel','orchestrat','cluster','agent','concurrent','per-agent','multi-head','multi-modal','federat']},
  // evez: falsifiability, provenance, spine — validated: Kathleen, MPPA
  {dim:'evez', weight:1.5, terms:['falsif','provenance','append','immutable','audit','verif','invariant','self-organiz','reproducib','reliable','traceable','deterministic','ground truth','benchmark']},
  // physics: first principles, conservation — validated: MPPA
  {dim:'physics', weight:1.2, terms:['meta-principle','endogenous','conservation','physics','deduct','first principle','embed','constraint','prior','inductive bias','physical','energy','symmetry','equivariant']},
  // efficiency: attention-free, linear complexity — validated: Kathleen
  {dim:'efficiency', weight:0.8, terms:['attention-free','token-free','linear complex','byte-level','zero-cost','efficient','O(L)','subquadratic','linear time','compressed','sparse','pruning','distill']},
];

function scoreAbstract(abstract, title) {
  const text = (abstract + ' ' + title).toLowerCase();
  const scores = {};
  let total = 0;
  for (const sig of EVEZ_SIGNALS) {
    const hits = sig.terms.filter(t => text.includes(t)).length;
    const s = Math.min(1.0, hits / 3) * sig.weight;
    scores[sig.dim] = +s.toFixed(3);
    total += s;
  }
  // Normalize total to 0-1
  const maxPossible = EVEZ_SIGNALS.reduce((a,s) => a + s.weight, 0);
  return {dimensions: scores, relevance: +(total / maxPossible).toFixed(4)};
}

// Map relevance score → CPF parameters
function inferCPFParams(relevance, dims) {
  // tau: driven by oscillator/temporal signals (1-10 range)
  const tau = Math.max(1, Math.round(1 + dims.tau * 9 + dims.physics * 3));
  // omega: phase coherence (0.5-1.0)
  const omega = +(0.5 + dims.omega * 0.5).toFixed(3);
  // N: agent count proxy (2-10)
  const N = Math.max(2, Math.round(2 + dims.N * 8));
  // topo: topology coefficient (1.0-3.0)
  const topo = +(1.0 + dims.topo * 2.0 + dims.evez * 0.5).toFixed(2);
  // poly_c = tau * omega * topo / (2 * sqrt(N))
  const poly_c = +(tau * omega * topo / (2 * Math.sqrt(N))).toFixed(4);
  return {tau, omega, N, topo, poly_c};
}

// ── SCORE ALL PAPERS ─────────────────────────────────────────────────────────
const scored = [];
for (const p of papers) {
  const {dimensions, relevance} = scoreAbstract(p.abstract, p.title);
  const cpf = inferCPFParams(relevance, dimensions);
  scored.push({...p, relevance, dimensions, ...cpf});
}

// Sort by poly_c descending
scored.sort((a,b) => b.poly_c - a.poly_c);

const canonical = scored.filter(p => p.poly_c >= 0.9);
const pending   = scored.filter(p => p.poly_c >= 0.5 && p.poly_c < 0.9);
const noise     = scored.filter(p => p.poly_c < 0.5);

// ── AI ENRICHMENT for top candidates (CANONICAL only) ────────────────────────
const enriched = [];
const SYS = `You are the EVEZ CPF Synthesis Engine operating above WF1-WF7.
You receive an arXiv paper abstract and return a FIRE event assessment.
EVEZ-OS architecture: CPF formula poly_c=tau*omega*topo/2*sqrt(N).
FIRE events are phase synchronization events — falsifiable, append-only, no edits ever.
Return ONLY valid JSON: {"fire_title":"str","domain":"str","description":"2 sentence synthesis mapping paper to EVEZ-OS","falsifier":"1 sentence specific falsifier","implications":["str","str"],"evez_bridge":"which EVEZ component this maps to"}`;

for (const p of canonical.slice(0, 5)) { // top 5 max to preserve API budget
  let ai = null;
  const prompt = `Paper: ${p.title}\nCategories: ${p.categories.join(', ')}\nAbstract: ${p.abstract}\n\npoly_c=${p.poly_c} tau=${p.tau} omega=${p.omega} N=${p.N} topo=${p.topo}`;

  if ($env.GROQ_API_KEY) {
    ai = await groq(SYS, prompt, 'llama-3.3-70b-versatile', 600);
    if (ai?.error) ai = null;
  }
  if (!ai && $env.GEMINI_API_KEY) {
    ai = await gemini(SYS, prompt, 600);
    if (ai?.error) ai = null;
  }

  const arxivId = p.id.split('v')[0];
  const fire_event = {
    event_type: 'FIRE_EVENT',
    title: ai?.fire_title || `arXiv ${arxivId} → EVEZ CPF Mapping`,
    domain: ai?.domain || p.categories[0] || 'EVEZ-OS',
    tau: p.tau, omega: p.omega, N: p.N, topo: String(p.topo),
    poly_c: p.poly_c,
    status: 'CANONICAL',
    description: ai?.description || `${p.title.slice(0,120)} — auto-detected poly_c=${p.poly_c} via WF8 CPF scanner.`,
    falsifier: ai?.falsifier || `If this paper\'s core result does not replicate on independent datasets, the EVEZ mapping is invalid.`,
    implications: ai?.implications || [p.title.slice(0,80), `poly_c=${p.poly_c} — CANONICAL threshold met`],
    evez_bridge: ai?.evez_bridge || 'CPF Engine',
    source_url: `https://arxiv.org/abs/${arxivId}`,
    paper_title: p.title,
    relevance_score: p.relevance,
    scan_query: query,
    powered_by: 'WF8 arXiv CPF Scanner / XyferViperZephyr',
    entry_hash: H({id:p.id, poly_c:p.poly_c}),
    ts,
    pid: 335,
  };

  await log('FIRE_EVENT', fire_event);
  enriched.push(fire_event);
}

// ── WEEKLY SCAN SUMMARY ──────────────────────────────────────────────────────
const summary = {
  event_type: 'ARXIV_SCAN_COMPLETE',
  ts, query, slot, pid: 335,
  papers_fetched: papers.length,
  canonical_count: canonical.length,
  pending_count: pending.length,
  noise_count: noise.length,
  fire_events_generated: enriched.length,
  top_paper: scored[0] ? {id:scored[0].id, title:scored[0].title.slice(0,80), poly_c:scored[0].poly_c} : null,
  canonical_papers: canonical.slice(0,10).map(p => ({id:p.id,title:p.title.slice(0,60),poly_c:p.poly_c,cats:p.categories.slice(0,2)})),
  all_scored: scored.map(p => ({id:p.id,title:p.title.slice(0,50),poly_c:p.poly_c,relevance:p.relevance})),
  entry_hash: H({slot, query, canonical_count: canonical.length}),
};

await log('ARXIV_SCAN_COMPLETE', summary);
return [{json: summary}];

// Commit this week's scan results to evez-autonomous-ledger
function H(d){let h=5381,s=typeof d==='string'?d:JSON.stringify(d);for(let i=0;i<s.length;i++){h=((h<<5)+h)+s.charCodeAt(i);h|=0;}return 'sha_'+Math.abs(h).toString(16).padStart(16,'0');}
async function log(t,p){try{await $fetch('https://evezos.app.n8n.cloud/webhook/evez-ledger',{method:'POST',body:{event_type:t,payload:{...p,pid:335,ts:new Date().toISOString()}}});}catch(e){}}

const scan = $input.first().json;
const token = $env.GITHUB_TOKEN || '';
if (!token) {
  await log('WF8_GITHUB_SKIP', {reason:'No GITHUB_TOKEN'});
  return [{json:{committed:false,reason:'No GITHUB_TOKEN set',...scan}}];
}

const OWNER = 'EvezArt';
const REPO  = 'evez-autonomous-ledger';
const ts    = new Date().toISOString();
const dateStr = ts.slice(0,10);

async function ghPut(path, content, msg) {
  const url = `https://api.github.com/repos/${OWNER}/${REPO}/contents/${path}`;
  const H2  = {'Authorization':`token ${token}`,'Accept':'application/vnd.github+json','Content-Type':'application/json','X-GitHub-Api-Version':'2022-11-28'};
  const existing = await $fetch(url+'?ref=main', {method:'GET', headers:H2}).catch(()=>null);
  const payload = {
    message: msg,
    content: btoa(unescape(encodeURIComponent(content))),
    branch: 'main',
    committer: {name:'WF8 arXiv Scanner / XyferViperZephyr', email:'wf8@evez-os.autonomous'},
  };
  if (existing?.sha) payload.sha = existing.sha;
  const r = await $fetch(url, {method:'PUT', headers:H2, body:payload});
  return r?.commit?.sha?.slice(0,10) || 'ok';
}

// Write weekly scan JSON
const scanPath   = `DECISIONS/arxiv_scans/scan_${dateStr}.json`;
const scanCommit = JSON.stringify({...scan, committed_by:'WF8', ts}, null, 2);
const sha1 = await ghPut(scanPath, scanCommit,
  `scan: arXiv CPF scan ${dateStr} — ${scan.canonical_count} CANONICAL, ${scan.papers_fetched} papers [WF8]`);

// Append to running FIRE events log if we generated any
let sha2 = null;
if (scan.fire_events_generated > 0) {
  const firePath = `DECISIONS/fire_events/wf8_auto_${dateStr}.json`;
  const fireCommit = JSON.stringify({
    generated_by: 'WF8 arXiv CPF Scanner',
    date: dateStr, ts,
    query: scan.query,
    fire_events_generated: scan.fire_events_generated,
    canonical_papers: scan.canonical_papers,
    top_paper: scan.top_paper,
    pid: 335,
    formula: 'poly_c=tau*omega*topo/2*sqrt(N)',
    witnessed_by: 'XyferViperZephyr',
  }, null, 2);
  sha2 = await ghPut(firePath, fireCommit,
    `fire: WF8 auto-generated ${scan.fire_events_generated} FIRE events from arXiv ${dateStr} [Cipher]`);
}

const result = {
  committed: true,
  scan_sha: sha1,
  fire_sha: sha2,
  scan_path: scanPath,
  papers: scan.papers_fetched,
  canonical: scan.canonical_count,
  fire_events: scan.fire_events_generated,
  top: scan.top_paper,
  ts, pid: 335,
};
await log('WF8_COMMITTED', result);
return [{json: result}];

